 // O(n) streaming — each feed() processes only new bytes
 const parser = vj.createParser();
 for await (const chunk of stream) {
-  if (parser.feed(chunk) === "complete") break;
+  const s = parser.feed(chunk);
+  if (s === "complete" || s === "end_early") break;
